def _dbm_to_vpeak(p_dbm, z0):
    """Convert power in dBm to peak voltage amplitude."""
    p_watts = 10.0 ** (p_dbm / 10.0) * 1e-3
    return np.sqrt(2.0 * z0 * p_watts)

